WITH toDate('2024-07-01') AS peak_month SELECT ( SELECT uniqExact(OriginCode) FROM ontime.fact_ontime WHERE Carrier = 'AA' AND Cancelled = 0 AND DepDelay IS NOT NULL AND toStartOfMonth(FlightDate) = peak_month ) AS total_origins_in_month, ( SELECT uniqExact(concat(OriginCode, '-', DestCode)) FROM ontime.fact_ontime WHERE Carrier = 'AA' AND Cancelled = 0 AND DepDelay IS NOT NULL AND toStartOfMonth(FlightDate) = peak_month ) AS total_routes_in_month, ( SELECT round(sumIf(total_departure_delay_minutes, rn <= 2) * 100.0 / max(total_delay_minutes), 2) FROM ( SELECT total_departure_delay_minutes, row_number() OVER (ORDER BY total_departure_delay_minutes DESC) AS rn, sum(total_departure_delay_minutes) OVER () AS total_delay_minutes FROM ( SELECT OriginCode, count() AS flight_volume, sum(DepDelayMinutes) AS total_departure_delay_minutes FROM ontime.fact_ontime WHERE Carrier = 'AA' AND Cancelled = 0 AND DepDelay IS NOT NULL AND toStartOfMonth(FlightDate) = peak_month GROUP BY OriginCode HAVING flight_volume >= 1000 ) ) ) AS top_2_origins_share_pct, ( SELECT round(sumIf(total_departure_delay_minutes, rn <= 5) * 100.0 / max(total_delay_minutes), 2) FROM ( SELECT total_departure_delay_minutes, row_number() OVER (ORDER BY total_departure_delay_minutes DESC) AS rn, sum(total_departure_delay_minutes) OVER () AS total_delay_minutes FROM ( SELECT OriginCode, count() AS flight_volume, sum(DepDelayMinutes) AS total_departure_delay_minutes FROM ontime.fact_ontime WHERE Carrier = 'AA' AND Cancelled = 0 AND DepDelay IS NOT NULL AND toStartOfMonth(FlightDate) = peak_month GROUP BY OriginCode HAVING flight_volume >= 1000 ) ) ) AS top_5_origins_share_pct, ( SELECT round(sumIf(total_departure_delay_minutes, rn <= 10) * 100.0 / max(total_delay_minutes), 2) FROM ( SELECT total_departure_delay_minutes, row_number() OVER (ORDER BY total_departure_delay_minutes DESC) AS rn, sum(total_departure_delay_minutes) OVER () AS total_delay_minutes FROM ( SELECT concat(OriginCode, '-', DestCode) AS route, count() AS flight_volume, sum(DepDelayMinutes) AS total_departure_delay_minutes FROM ontime.fact_ontime WHERE Carrier = 'AA' AND Cancelled = 0 AND DepDelay IS NOT NULL AND toStartOfMonth(FlightDate) = peak_month GROUP BY route HAVING flight_volume >= 200 ) ) ) AS top_10_routes_share_pct
